**Complexity: Medium (83 lines, with OCaml bridge integration)**

```cpp
void init_points(polymodel *pm,vms_vector *box_size,int submodel_num,morph_data *md)
{
	uint16_t nverts;
	vms_vector *vp;
	uint16_t *data,type;
	int i;

	//printf("initing %d ",submodel_num);
	data = (uint16_t *) &pm->model_data[pm->submodel_ptrs[submodel_num]];

	type = *data++;

	Assert(type == 7 || type == 1);

	nverts = *data++;

	md->n_morphing_points[submodel_num] = 0;

	if (type==7) 
	{
		i = *data++;		//get start point number
		data++;				//skip pad
	}
	else
		i = 0;				//start at zero

	Assert(i+nverts < MAX_VECS);

	md->submodel_startpoints[submodel_num] = i;

	vp = (vms_vector *) data;

#ifdef USE_OX_BRIDGE
	if (cd_ox_is_ready()) {
		int morph_slot = (int)(md - morph_objects);
		int32_t nmp = md->n_morphing_points[submodel_num];
		cd_ox_update_points(morph_slot, submodel_num,
			FrameTime, nverts, i, &nmp,
			&md->morph_times[i],
			(int32_t*)&md->morph_vecs[i],
			(int32_t*)&md->morph_deltas[i],
			(int32_t*)vp);
		md->n_morphing_points[submodel_num] = nmp;
		return;
	}
#endif

	while (nverts--) 
	{
		fix k,dist;

		if (box_size) 
		{
			fix t;

			k = 0x7fffffff;

			if (vp->x && f2i(box_size->x)<abs(vp->x)/2 && (t = fixdiv(box_size->x,abs(vp->x))) < k) k=t;
			if (vp->y && f2i(box_size->y)<abs(vp->y)/2 && (t = fixdiv(box_size->y,abs(vp->y))) < k) k=t;
			if (vp->z && f2i(box_size->z)<abs(vp->z)/2 && (t = fixdiv(box_size->z,abs(vp->z))) < k) k=t;

			if (k==0x7fffffff) k=0;

		}
		else
			k=0;

		vm_vec_copy_scale(&md->morph_vecs[i],vp,k);

		dist = vm_vec_normalized_dir_quick(&md->morph_deltas[i],vp,&md->morph_vecs[i]);

		md->morph_times[i] = fixdiv(dist,morph_rate);

		if (md->morph_times[i] != 0)
			md->n_morphing_points[submodel_num]++;

		vm_vec_scale(&md->morph_deltas[i],morph_rate);

		vp++; i++;

	}
	//printf("npoints = %d\n",n_morphing_points[submodel_num]);
}
```

**Purpose:** Initializes morph data points for a polygon model submodel. Extracts vertex data from the model, calculates morphing times and delta vectors for each vertex. Has an OCaml bridge hook for potential future porting.

