    v_result = caml_callbackN(*g_do_controlcen_frame_d1, 27, args);

    result[0] = Int_val(Field(v_result, 0));
    result[1] = Int_val(Field(v_result, 1));
    result[2] = Int_val(Field(v_result, 2));
