void explode_wall(int segnum,int sidenum)
{
#ifdef USE_OX_BRIDGE
	if (cd_ox_is_ready()) {
		cd_ox_explode_wall(segnum, sidenum);
		return;
	}
#endif

	int i;
	vms_vector pos;

